"""
Professional SVG icon library for the Cattle Health Monitoring System.
Replaces emoji usage with clean, scalable inline SVGs.
Each icon is a 16x16 SVG string that can be embedded in HTML.
"""


def _svg(path_d: str, color: str = "currentColor", size: int = 16) -> str:
    """Wrap an SVG path in a properly-sized container."""
    return (
        f'<svg width="{size}" height="{size}" viewBox="0 0 16 16" fill="{color}" '
        f'style="display:inline-block;vertical-align:text-bottom;margin-right:4px;">'
        f'<path d="{path_d}"/></svg>'
    )


